var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 9월 30일 런던, 화이트 채플","JPN":"1888年9月30日　ロンドン、ホワイトチャペル","ENG":"September 30, 1888, London, White Chapel","TWN":"1888年9月30日 倫敦，白教堂"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PAWNSHOP_SWANSONG_NPC_NULL","text":{"KOREA":"들어오쇼.","JPN":"どうぞ。","ENG":"Come in.","TWN":"進來吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PAWNSHOP_SWANSONG_NPC_NULL","text":{"KOREA":"수녀님이시구먼, 여긴 어쩐 일로 오셨소?","JPN":"シスターさんかい。ここにはなんの用ですか？","ENG":"Sister? What brings you here?","TWN":"修女，你怎麼來這裡了？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"파노라마를 극장 밖에서 쓰겠다고요?","JPN":"パノラマを劇場の外で使うですって！？","ENG":"You wish to use Panorama outside of the theater?","TWN":"你說要在劇院外使用全景？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"미쳤어요? 왕실 마도구를 허가없이 반출하는 건, 중대한 범죄라고요!","JPN":"正気ですか？　王室の魔道具を許可なしで搬出するのは重罪ですよ！","ENG":"Are you mad? Taking out the royal Curio without permission is a serious crime!","TWN":"你瘋了嗎？擅自帶出王室魔法道具可是重大的犯罪行為！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 괜찮아.","JPN":"ふふ、大丈夫だ。","ENG":"Haha, it'll be fine.","TWN":"呵呵，不會那麼嚴重的。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네의 전속 스태프, 메리 제인 양은 오늘 하루 휴가를 내지 않았나?","JPN":"君の専属スタッフ、メリー・ジェーン嬢は今日一日休みを取っているだろう。","ENG":"Hasn't your personal staff, Mary Jane, taken the entire day off today?","TWN":"你的專屬職員，瑪麗·珍今天不是請假了嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"한 개쯤, 조용히 쓰고 돌려놓으면 아무런 문제가 되지 않을 걸세.","JPN":"こっそり使って戻しておけば一つくらい大したことないさ。","ENG":"It won't be a problem if we take one out quietly and return it before anyone notices.","TWN":"拿走一個，用完再悄悄放回去，不會有任何問題的。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"무슨 그런 안일한 생각을! 이건 배우로서 커리어가 달린 문제예요!","JPN":"なんて甘い考え方…！　これは役者のキャリアに関わる問題です！","ENG":"That's so reckless! This is my career on the line!","TWN":"怎麼能有那種輕率的想法！這是關乎我演員生涯的大事啊！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"다른 사람에게 들켰다간 그냥 끝나지 않을 거라고요!","JPN":"バレたらただじゃ済みませんから！","ENG":"If someone sees me, it won't end well!","TWN":"如果被其他人發現的話，可就完蛋了！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"으음? 들킨다고? 그거 이상하군.","JPN":"ん？　バレる？　おかしなことを言うな。","ENG":"Mm? Sees you? That's odd.","TWN":"嗯？被發現了？那可真奇怪。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네 정도의 배우라면 어떤 상황도, 어떤 배역도 완벽히 소화할 수 있다고 생각했는데.","JPN":"君ほどの役者なら、どんな状況でも、どんな役でも完璧にやりすごせると思っていたが。","ENG":"I thought an actress of your stature could handle any role in any situation perfectly.","TWN":"我原以為像你這樣的演員，無論什麼情況，無論什麼角色都能完美駕馭。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"설령, 그게 사전에 준비된 무대 위가 아닐지라도 말이야.","JPN":"たとえそれが、事前に用意された舞台の上じゃなくてもな。","ENG":"Even if it's not on a stage prepared in advance.","TWN":"即使那不是事先準備好的舞台。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"뭐라고요……?","JPN":"なんですって……？","ENG":"What...?","TWN":"你說什麼……？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"뭐, 어쩔 수 없겠지. 자네가 도저히 못 하겠다면, 나도 다른 방법을…….","JPN":"まあ、仕方ないだろう。君がどうしても無理だというなら、他の方法を……","ENG":"Oh, well. If you can't do it, I'll have to find another way–","TWN":"不過，沒辦法了。如果你實在做不到的話，我也只能另想辦法……。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"잠깐.","JPN":"待って。","ENG":"Wait.","TWN":"等一下。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그 발언, 지금 제 실력을 의심하는 건가요?","JPN":"今の発言、私の実力を疑っているんですか？","ENG":"Are you doubting my skills right now?","TWN":"你這話，是在懷疑我的實力嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"참 무례하시네요.","JPN":"まったくもって失礼ですね。","ENG":"Rude doesn't even describe your behavior.","TWN":"真是無禮啊。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"여기서 얌전히 기다리기나 하세요.","JPN":"ここで大人しく待っていてください。","ENG":"You just wait here.","TWN":"在這裡乖乖等著吧。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"보란 듯이 정보를 얻어내서 그 경솔한 발언, 사과하게 만들어 드릴 테니까!","JPN":"見事情報を手に入れて、先程の発言を謝罪させますから！","ENG":"I'll make you eat your words and apologize to me by getting that information!","TWN":"我會拿到資訊，讓你為自己輕率的言論道歉！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이걸로 다섯 번째 가게…….","JPN":"これで五か所目……","ENG":"This should be the fifth shop...","TWN":"這是第五家店了……"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"곰곰이 생각해보니, 또 욱해서 그 남자에게 휘말려 버린 것 같지만.","JPN":"よく考えてみたら、またついカッとなってあの男の計画にはめられた気がするけど。","ENG":"Come to think of it, it seems I got angry and got caught up in that man's tomfoolery again.","TWN":"仔細想想，好像又因為衝動被那個男人牽著鼻子走了。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"좋아. 이왕 이렇게 된 거, 그 잘난 척하는 콧대를 눌러주겠어.","JPN":"いいわ、こうなった以上あの偉そうな男をぎゃふんと言わせてやる。","ENG":"All right. Since it has already come to this, I'll make sure to flatten that snobby nose of his.","TWN":"好吧，既然這樣，一定要打壓一下他那自以為是的傲氣。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"주님의 은총이 그대에게 가득하길.","JPN":"主の恩寵がともにありますように。","ENG":"May the Lord's grace be with you.","TWN":"願主的恩典與你同在。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"저, 이 가게에서 마석을 취급한다는 이야기를 들었습니다만…….","JPN":"あの、このお店で魔石を扱っているとお聞きしましたが……","ENG":"Um, I heard that this shop handles Mana Stones...","TWN":"那個，我聽說這家店有賣魔石……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PAWNSHOP_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PAWNSHOP_SWANSONG_NPC_NULL","text":{"KOREA":"이능력자요?","JPN":"異能力者ですか？","ENG":"Are you a Supernatural?","TWN":"超能力者嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"저는 아니에요. 하지만…….","JPN":"私ではありません。ただ……","ENG":"Not me, but...","TWN":"不，不是我。是……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이능력자들은 살아가는데 필연적으로 마석이 필요하다네.","JPN":"異能力者は、生きるためには魔石が必要不可欠だ。","ENG":"Supernaturals inevitably need Mana Stones to survive.","TWN":"超能力者在生活中必然需要魔石。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 마석 값을 지불할 수 없는 능력자들은 런던에 수도 없이 많아.","JPN":"だが魔石の代金を支払えない異能力者はロンドンに溢れている。","ENG":"But most of them can't even afford to pay for one.","TWN":"但無法支付魔石費用的超能力者在倫敦多得難以計數。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 그건 이능력자가 아닌, 중산 계층도 마찬가지야.","JPN":"異能力者だけではない、中流階級にとっても他人事ではないのだよ。","ENG":"It's the same for the middle class as well.","TWN":"即使是中產家庭也是如此。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"어느 날, 가족 구성원 중에 이능력자가 생기면, 순식간에 하층민으로 전락하게 되니까.","JPN":"ある日突然家族が異能力者として覚醒してしまったら、あっという間に下層民になり下がってしまう。","ENG":"One day, if a family member suddenly becomes a Supernatural, then it's a quick fall to the lower class.","TWN":"若是家中出現了一名能力者，那表示他們很快就會淪為下層民了。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"보육원 중에는 그렇게 버려진 아이들도 많다네.","JPN":"孤児院にはそうやって捨てられた子がたくさんいるのだよ。","ENG":"Some of the children being even abandoned to orphanages.","TWN":"甚至有些會把孩子送到孤兒院去。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"교회에서 작은 보육원을 운영하고 있답니다만.","JPN":"教会で小さな孤児院を運営しているのですが。","ENG":"The church is running a small orphanage.","TWN":"教會在運營一個小型孤兒院。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"며칠 전, 한 아이가 증표를…….","JPN":"数日前に、そこの子に印が……","ENG":"And a few days ago, a child got a mark...","TWN":"幾天前，一個孩子出現了印記……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PAWNSHOP_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"신부님께서는 문제가 발생하기 전에 그 아이를 퇴소시키자고 했지만…….","JPN":"神父様は問題が起こる前にその子を退所させようと言っていますが……","ENG":"The priest suggested sending that child away before any problems arose...","TWN":"神父說要趁早把那個孩子送出去，可是……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"그러기엔 아이가 너무 어려서요.","JPN":"一人で生きるにはまだ幼すぎるのです。","ENG":"But the child was too young for us to not take in.","TWN":"可是孩子太小了。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PAWNSHOP_SWANSONG_NPC_NULL","text":{"KOREA":"소용없는 일이오.","JPN":"無駄ですよ。","ENG":"It's all in vain.","TWN":"沒用的。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PAWNSHOP_SWANSONG_NPC_NULL","text":{"KOREA":"마석 값이 하늘 높은 줄 모르고 치솟고 있으니…….","JPN":"魔石の値は天井知らずに上がっている。","ENG":"The price of Mana Stones keeps going up...","TWN":"魔石的價格飛漲，現在簡直高得離譜……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PAWNSHOP_SWANSONG_NPC_NULL","text":{"KOREA":"결국, 불쌍한 아이도 곧 길바닥에 나앉게 되겠지.","JPN":"そのうち可哀想なその子も物乞いになるでしょう。","ENG":"Eventually, that poor child will end back up on the streets.","TWN":"那個可憐的孩子最終還是會被趕上街頭吧。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"그래도…….","JPN":"でも……","ENG":"But still...","TWN":"不過……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"그래도 그 아이를 위해, 제가 할 수 있는 일이 있다면…….","JPN":"それでもあの子のために、私にできることがあれば……","ENG":"If there is anything I can do for the child...","TWN":"即便如此，為了那個孩子，如果我能做些什麼……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PAWNSHOP_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PAWNSHOP_SWANSONG_NPC_NULL","text":{"KOREA":"물건은?","JPN":"ブツは？","ENG":"What are you trading in?","TWN":"東西呢？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"미사 때 쓰는 은촛대를 준비해왔답니다.","JPN":"礼拝の時に使う、銀の燭台です。","ENG":"I've brought a silver candle holder used for mass.","TWN":"我、我準備了彌撒時用的銀燭臺！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"신부님께서는 100년도 넘은 물건이라고 하셨어요.","JPN":"神父様は100年も前に作られた逸品だと言っていました。","ENG":"The priest said it was over a hundred years old.","TWN":"神父說這是超過100年的老物件了。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PAWNSHOP_SWANSONG_NPC_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PAWNSHOP_SWANSONG_NPC_NULL","text":{"KOREA":"진품이로군.","JPN":"本物ですな。","ENG":"It's authentic.","TWN":"嗯……是真的。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PAWNSHOP_SWANSONG_NPC_NULL","text":{"KOREA":"조용히 따라오시오. 아는 공급처가 있으니.","JPN":"静かについて来てください。知り合いの供給先がある。","ENG":"Follow me quietly. I know a supplier.","TWN":"安靜地跟我來。我知道有個供應商。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 9월 30일 런던, <color=#ffd34c>황금 새벽회</color> 지하 사원","JPN":"1888年9月30日　ロンドン、<color=#ffd34c>黄金の暁団</color>地下寺院","ENG":"September 30, 1888, London, <color=#ffd34c>Golden Dawn</color> Underground Temple","TWN":"1888年9月30日 倫敦，<color=#ffd34c>黃金黎明會</color>地下神廟"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"여긴 대체……?","JPN":"ここはいったい……","ENG":"What is this place...?","TWN":"這裡到底是……？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"저희 황금 새벽회의 사원에 오신 걸 환영합니다. 이교도여.","JPN":"我々黄金の暁団にようこそ、異教徒よ。","ENG":"Welcome to the temple of the Golden Dawn, pagan.","TWN":"歡迎來到我們的黃金黎明會，異教徒。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"황금 새벽회라고요?","JPN":"黄金の暁団？","ENG":"The Golden Dawn?","TWN":"黃金黎明會？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"이상하네요. 왕국에서 인정하고 있는 국교는 오직 하나뿐일 텐데요?","JPN":"おかしいですね。王国が認めている国教は一つだけのはずです。","ENG":"How strange. I was told that there's only one national religion that was recognized in the kingdom.","TWN":"真奇怪。我以為王國承認的國教應該只有一個……？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그 교리는 아무도 구원해 줄 수 없죠.","JPN":"ですが、その教理では誰も救われない。","ENG":"But their doctrine cannot save anyone.","TWN":"但憑他們的教義誰也救不了。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"마그눔 오푸스. 황금 새벽회는 마석을 연성할 수 있는 연금술을 알고 있답니다.","JPN":"マグヌム・オプス。黄金の暁団は魔石を錬成できる錬金術を知っているのです。","ENG":"Magnum Opus. The Golden Dawn knows alchemy that can transmute Mana Stones.","TWN":"偉大傑作在上。我們黃金黎明會知道如何煉製魔石的煉金術。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"따라서 이 나라의 수많은 빈민들에게 실질적인 구원을 내릴 수 있지요.","JPN":"よって、この国にいる数多くの貧民を救うことができます。","ENG":"Thus, we are able to bring real salvation to the poor.","TWN":"因此，可以對這個國家的眾多貧民提供實質性的救助。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"마석을 연성한다고요? 대체 어떻게……?","JPN":"魔石を錬成する……？　いったいどうやって…？","ENG":"Transmute Mana Stones? How's that possible...?","TWN":"煉金術？到底是怎麼……？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"제조 과정은 간단하답니다.","JPN":"製造過程は簡単です。","ENG":"The process is rather simple.","TWN":"製造過程很簡單。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>니그레도</color>. 먼저, 흑화의 과정을 거쳐.","JPN":"<color=#ffd34c>ニグレド</color>。まず黒化の過程を経て。","ENG":"<color=#ffd34c>Nigredo</color>. First, it goes through the blackening process.","TWN":"<color=#ffd34c>尼格列多</color>。首先，要經過黑化階段。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>알베도</color>. 백으로써 정화하여.","JPN":"<color=#ffd34c>アルベド</color>。白をもって浄化し。","ENG":"<color=#ffd34c>Albedo</color>. Then purified into white.","TWN":"<color=#ffd34c>艾爾貝多</color>。白化，以白色淨化。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>루베도</color>. 비로소 적색의 마석을 연성할 수 있는 거죠.","JPN":"<color=#ffd34c>ルベド</color>。ようやく赤色の魔石が錬成されるのです。","ENG":"<color=#ffd34c>Rubedo</color>. And finally, we transmute them into crimson Mana Stones.","TWN":"<color=#ffd34c>露貝多</color>。最後是紅化，這一步就可以煉出深紅色的魔石了。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"런던의 이능력자들은 혐오와 멸시의 대상입니다.","JPN":"ロンドンの異能力者は忌み嫌われ、蔑まれています。","ENG":"Supernaturals are viewed with hatred in London.","TWN":"倫敦的超能力者們是被憎惡和蔑視的對象。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"그들이 살기 위해서는 마석이 필요하지만, 값비싼 마석을 베푸는 이들은 아무도 없죠.","JPN":"彼らが生きるためには魔石が必要ですが、彼らのために貴重な魔石を施す人は誰一人いません。","ENG":"They need Mana Stones to survive, but no one is willing to provide them with costly Mana Stones.","TWN":"他們為了生存需要魔石，但沒有人願意施捨昂貴的魔石。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 저희 교단은 다르답니다.","JPN":"ですが我々は違いますよ。","ENG":"However, our order is different.","TWN":"但我們教團不同。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"정말로 마석을……?","JPN":"本当に魔石を……？","ENG":"Is that really Mana Stones...?","TWN":"那個真的是魔石……？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"자, 어떠신가요?","JPN":"さあ、いかがなさいますか？","ENG":"What do you think?","TWN":"那麼，你覺得怎麼樣？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"저희와 함께 하실 건가요, 자매여.","JPN":"私たちと、意志をともにしますか。","ENG":"Would you be willing to join us, Sister?","TWN":"你願意和我們一起嗎，姐妹？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 9월 30일 런던, 화이트 채플\\n<color=#ffd34c>심야</color>","JPN":"1888年9月30日　ロンドン、ホワイトチャペル\\n<color=#ffd34c>深夜</color>","ENG":"September 30, 1888, London, White Chapel,\\n<color=#ffd34c>Midnight</color>","TWN":"1888年9月30日 倫敦，白教堂 <color=#ffd34c>深夜</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WOMAN_SWANSONG_NPC_NULL","text":{"KOREA":"사, 살려주세요……!!","JPN":"た、助けてください……！！","ENG":"S-somebody help me...!!","TWN":"救，救命……！！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"WOMAN_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마가……!!","JPN":"深夜の殺人鬼が……！！","ENG":"The Midnight Killer...!!","TWN":"午夜殺人魔……！！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RIPPER_SWANSONG_NPC_QM","text":{"KOREA":"……이걸로 세번째.","JPN":"……これで三つ目。","ENG":"...The third one.","TWN":"……這已經是第三次了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIPPER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RIPPER_SWANSONG_NPC_QM","text":{"KOREA":"<color=#ffd34c>그 남자</color>의 말대로 메시지는 남겼어. 다음은…….","JPN":"<color=#ffd34c>あの男</color>の言う通りに、メッセージは残した。次は……","ENG":"A message was left behind just like <color=#ffd34c>the man</color> said. Next is...","TWN":"<color=#ffd34c>那個男人</color>的話我已經傳達了。接下來是……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIPPER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RIPPER_SWANSONG_NPC_QM","text":{"KOREA":"마침, 다음 제물의 위치가 이 근처로군.","JPN":"ちょうど次の生贄がいる場所はこの辺。","ENG":"Alas, the next offering's location is nearby.","TWN":"正好，下一個祭品的位置就在附近。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIPPER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RIPPER_SWANSONG_NPC_QM","text":{"KOREA":"하지만 수사망이 점점 좁혀오고 있어. 꼬리가 길면 밟히는 법이지.","JPN":"しかし捜査網が迫ってきている。無理をしたら尻尾を掴まれるかもしれない。","ENG":"But the police are closing in. I need to be more cautious from now on.","TWN":"但是調查網正在逐漸收緊。俗話說常在河邊走……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIPPER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RIPPER_SWANSONG_NPC_QM","text":{"KOREA":"무리하지 않는 편이…… ","JPN":"様子をみたほうが…… ","ENG":"It's best not to get carried away–","TWN":"嗯，有些勉強……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIPPER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RIPPER_SWANSONG_NPC_QM","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIPPER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"……크윽!","JPN":"……くっ！","ENG":"...Kgh!","TWN":"……咳！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"또 너로군.","JPN":"また貴様か。","ENG":"It is you again.","TWN":"又是你。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_QM","text":{"KOREA":"……가엾은 자여.","JPN":"……哀れな者よ。","ENG":"...Oh, ye woeful fool.","TWN":"……可憐的人啊。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_QM","text":{"KOREA":"결정을 뒤집기는 쉬우나 후회를 막기는 어렵도다.","JPN":"決定を覆すことは簡単だが、後悔を防ぐことは難しい。","ENG":"Decisions may be easy to overturn, but regret remains forever.","TWN":"決定容易推翻，但後悔卻難以阻止。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_QM","text":{"KOREA":"그러니 지금이라도 우행을 멈춰라.","JPN":"故に、今からでも愚行を絶つのだ。","ENG":"So stop your foolishness now.","TWN":"現在停止你的愚行吧。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"웃기지 마.","JPN":"ふざけるな。","ENG":"Don’t make me laugh.","TWN":"別開玩笑了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"모든 복수를 완수할 때까지……. 억울하게 죽은 아이를 다시 보게 될 때까지……!","JPN":"すべての復讐を完遂するまで……無念に死んでしまったあの子にまた再会するまで……！","ENG":"Until all vengeance is fulfilled... Until I'm reunited with the child who died unjustly...!","TWN":"在完成所有復仇之前……在見到冤死的孩子之前……！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"나는 무슨 일이 있어도 멈추지 않을 테니까……!","JPN":"私は何があっても止まらない……！","ENG":"I will not stop! No matter what...!","TWN":"無論發生什麼，我都不會停下……！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"모든 것은 각본대로.","JPN":"すべては脚本どおりに。","ENG":"Everything according to the script.","TWN":"一切都將按照劇本進行。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};